  <div class="vintage-prologue" id="prologue-container">
    <!-- ✨ 替换说明：
         直接把下面按钮文本里的“🍎”换成任意 emoji（如 🍋 / 🌙 / ☀️），无需修改 JS 或 CSS。 -->
    <button id="prologue-theme-btn" class="prologue-emoji" aria-label="切换主题" title="切换主题">🍎</button>

    <div class="content">
      <div class="main-text" id="main-text-container"></div>
      <p class="source-text" id="prologue-source"></p>
    </div>
